(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim();
let overlay,body,selected=new Set(),installed=false;
function fmt(d){return d.toISOString().slice(0,10)}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function daysBetween(a,b){const out=[],sa=new Date(a+'T00:00:00'),sb=new Date(b+'T00:00:00');if(isNaN(sa)||isNaN(sb))return out;for(let d=new Date(sa);d<=sb;d.setDate(d.getDate()+1))out.push(fmt(d));return out}
function css(){if($('#dateCheckStyle263'))return;const st=document.createElement('style');st.id='dateCheckStyle263';st.textContent=`.datePickBtn{height:34px;border:1px solid #087b34;background:#f0fdf4;color:#087b34;border-radius:8px;padding:0 10px;font-weight:950;margin-left:8px}.dateOverlay{position:fixed;inset:0;background:rgba(15,23,42,.45);z-index:170;display:none;align-items:flex-end;justify-content:center}.dateOverlay.on{display:flex}.dateSheet{width:min(96vw,520px);max-height:82vh;background:#fff;border-radius:18px 18px 0 0;box-shadow:0 -18px 60px #0004;display:flex;flex-direction:column;overflow:hidden}.dateHead{background:#087b34;color:#fff;padding:12px 14px;display:flex;justify-content:space-between;align-items:center;gap:8px}.dateHead b{font-size:16px}.dateClose{height:32px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.dateBody{padding:10px;overflow:auto}.dateGrid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.dateItem{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:9px 8px;font-weight:900;text-align:left;display:flex;gap:8px;align-items:center}.dateItem.on{border-color:#087b34;background:#ecfdf5;color:#065f27}.dateItem i{width:18px;height:18px;border:1px solid #9ca3af;border-radius:5px;display:inline-grid;place-items:center;font-style:normal;font-size:13px}.dateItem.on i{background:#087b34;color:#fff;border-color:#087b34}.dateFoot{padding:10px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px}.dateFoot button{height:42px;border-radius:10px;font-weight:950}.dateClear{border:1px solid #d1d5db;background:#fff;color:#4b5563}.dateToday{border:1px solid #22c55e;background:#f0fdf4;color:#087b34}.dateOk{border:0;background:#087b34;color:#fff}.dateHint{font-size:12px;color:#4b5563;line-height:1.45;margin-bottom:8px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:8px}.dateCardFilters{margin-top:12px}.dateCardFilters.card{box-shadow:none;border-color:#bbf7d0;background:#f0fdf4}.dateCardFilters h3{display:none}.dateCardFilters .filterGrid{grid-template-columns:1fr!important;gap:8px}.dateCardFilters .searchLine{grid-template-columns:1fr!important;gap:8px;margin-top:8px}.dateCardFilters .mobileHint{font-size:11px}.dateCardFilters .field input,.dateCardFilters .field select{height:38px}.dateCardFilters .range{grid-template-columns:1fr 20px 1fr}.dateCardFilters .clear,.dateCardFilters .searchBtn{height:38px}@media(max-width:420px){.dateGrid{grid-template-columns:repeat(2,1fr)}}`;document.head.appendChild(st)}
function ensure(){css();if(!overlay){overlay=document.createElement('div');overlay.className='dateOverlay';overlay.innerHTML='<div class="dateSheet"><div class="dateHead"><b>เลือกวันที่แบบติ๊กมาร์ก</b><button class="dateClose">ปิด</button></div><div class="dateBody"></div><div class="dateFoot"><button class="dateClear">ล้าง</button><button class="dateToday">วันเดียว</button><button class="dateOk">ตกลง</button></div></div>';document.body.appendChild(overlay);body=overlay.querySelector('.dateBody');overlay.querySelector('.dateClose').onclick=close;overlay.querySelector('.dateClear').onclick=()=>{selected.clear();render()};overlay.querySelector('.dateToday').onclick=()=>{const s=$('#startDate')?.value||$('#endDate')?.value;if(s){selected.clear();selected.add(s);render()}};overlay.querySelector('.dateOk').onclick=apply;overlay.onclick=e=>{if(e.target===overlay)close()}}}
function sourceRange(){const s=$('#startDate')?.value,e=$('#endDate')?.value;if(s&&e)return{s,e};const today=fmt(new Date());return{s:s||today,e:e||s||today}}
function open(){ensure();const {s,e}=sourceRange();selected=new Set(daysBetween(s,e));render();overlay.classList.add('on')}
function close(){overlay?.classList.remove('on')}
function render(){const {s,e}=sourceRange();const all=daysBetween(s,e);body.innerHTML='<div class="dateHint">ติ๊กวันที่ที่ต้องการ แล้วกด “ตกลง” ระบบจะตั้งช่วงวันที่จากวันแรกถึงวันสุดท้ายที่เลือก</div><div class="dateGrid">'+all.map(d=>`<button class="dateItem ${selected.has(d)?'on':''}" data-d="${d}"><i>${selected.has(d)?'✓':''}</i><span>${thai(d)}</span></button>`).join('')+'</div>';body.querySelectorAll('.dateItem').forEach(b=>b.onclick=()=>{const d=b.dataset.d;if(selected.has(d))selected.delete(d);else selected.add(d);render()})}
function apply(){const arr=[...selected].sort();if(arr.length){const s=$('#startDate'),e=$('#endDate');s.value=arr[0];e.value=arr[arr.length-1];s.dispatchEvent(new Event('change',{bubbles:true}));e.dispatchEvent(new Event('change',{bubbles:true}));const p=$('#datePreview');if(p)p.textContent=arr.length===1?thai(arr[0]):`${thai(arr[0])} - ${thai(arr[arr.length-1])}`}close()}
function moveFilters(){const filters=document.querySelector('section.filters'),dateCard=document.querySelector('#upload .topGrid .card:nth-child(2)');if(filters&&dateCard&&!filters.dataset.movedToDate){filters.dataset.movedToDate='1';filters.classList.add('dateCardFilters');dateCard.appendChild(filters)}}
function install(){ensure();moveFilters();const box=document.querySelector('.dateBox');if(box&&!$('#datePickBtn')){const b=document.createElement('button');b.id='datePickBtn';b.type='button';b.className='datePickBtn';b.textContent='✓ เลือกวัน';box.appendChild(b);b.onclick=e=>{e.stopPropagation();open()};box.onclick=open}const labels=[...document.querySelectorAll('.field label')];labels.forEach(l=>{if(l.textContent.includes('ช่วงวันที่'))l.textContent='ช่วงวันที่ / ติ๊กมาร์ก'});['startDate','endDate'].forEach(id=>{const el=$('#'+id);if(el&&!el.dataset.dateMark263){el.dataset.dateMark263='1';el.readOnly=true;el.addEventListener('click',e=>{e.preventDefault();open()})}});installed=true}
document.addEventListener('DOMContentLoaded',()=>{install();setTimeout(install,600);setTimeout(install,1600)});if(document.readyState!=='loading')install();
})();
